const item = $input.item;
const bin = item?.binary || $binary || {};
const keys = Object.keys(bin);

if (!keys.length) {
  const jsonKeys = Object.keys(item?.json || {});
  throw new Error(`No se recibió archivo binario. Keys json recibidas: ${jsonKeys.join(', ') || '(ninguna)'}. Envía multipart/form-data con un archivo.`);
}

const preferred = ['file', 'invoice', 'data'];
const fileKey = preferred.find((k) => keys.includes(k)) || keys[0];
const b = bin[fileKey];
const mimeType = String(b?.mimeType || '').toLowerCase();

if (!mimeType.startsWith('image/')) {
  throw new Error(`Archivo no válido (${mimeType || 'sin mimeType'}). Solo se permiten imágenes.`);
}

const itemIndex = typeof $input.itemIndex === 'number' ? $input.itemIndex : 0;
const buffer = await this.helpers.getBinaryDataBuffer(itemIndex, fileKey);
const base64 = buffer.toString('base64');

const now = new Date();
const timestamp = now.toISOString().replace(/[.:]/g, '-');

return [{
  json: {
    sourceBinaryKey: fileKey,
    fileName: b.fileName || `factura-${timestamp}.${b.fileExtension || 'jpg'}`,
    mimeType: mimeType || 'image/jpeg',
    imageBase64: base64,
    imageDataUrl: 'data:' + (mimeType || 'image/jpeg') + ';base64,' + base64
  },
  binary: {
    invoiceImage: b,
    data: b
  }
}];

const mergedData = $('Esperar Drive y OCR').first().json;

let parsed = {};

if (mergedData.candidates && mergedData.candidates.length > 0) {
  let rawText = mergedData.candidates[0].content.parts[0].text || '{}';
  if (typeof rawText === 'string') {
    rawText = rawText.replace(/^\s*```(json)?/im, '').replace(/\s*```\s*$/im, '').trim();
  }
  try {
    parsed = JSON.parse(rawText || '{}');
  } catch (e) {
    throw new Error('El modelo no devolvió un JSON válido. Respuesta: ' + rawText);
  }
} else {
  throw new Error('No se encontraron datos en la respuesta de la IA.');
}

const rows = [];

// Función para limpiar nulos
const safeStr = (v) => v !== undefined && v !== null ? String(v) : '';

// 1. Procesar Encabezado Dinámico
if (Array.isArray(parsed.encabezado)) {
    for (let i = 0; i < parsed.encabezado.length; i += 2) {
        const item1 = parsed.encabezado[i];
        const item2 = i + 1 < parsed.encabezado.length ? parsed.encabezado[i + 1] : null;

        // Fila de Campos
        rows.push({
            " ": item1.campo ? safeStr(item1.campo).toUpperCase() : "",
            "  ": "",
            "   ": item2 && item2.campo ? safeStr(item2.campo).toUpperCase() : "",
            "    ": ""
        });

        // Fila de Valores
        rows.push({
            " ": item1.valor ? safeStr(item1.valor) : "",
            "  ": "",
            "   ": item2 && item2.valor ? safeStr(item2.valor) : "",
            "    ": ""
        });

        // Espaciador
        rows.push({ " ": "", "  ": "", "   ": "", "    ": "" });
    }
} else {
    // Fallback space
    rows.push({ " ": "", "  ": "", "   ": "", "    ": "" });
}

// 2. Procesar Columnas Dinámicas de la Tabla
if (Array.isArray(parsed.columnas_tabla)) {
    const colA = safeStr(parsed.columnas_tabla[0]);
    const colB = safeStr(parsed.columnas_tabla[1]);
    const colC = safeStr(parsed.columnas_tabla[2]);
    const colD = safeStr(parsed.columnas_tabla[3]);

    // Títulos de tabla
    rows.push({ " ": colA, "  ": colB, "   ": colC, "    ": colD });

    // 3. Procesar Filas de la Tabla
    if (Array.isArray(parsed.tabla_items)) {
        parsed.tabla_items.forEach(itemArray => {
            if (Array.isArray(itemArray)) {
                rows.push({
                    " ": safeStr(itemArray[0]),
                    "  ": safeStr(itemArray[1]),
                    "   ": safeStr(itemArray[2]),
                    "    ": safeStr(itemArray[3])
                });
            }
        });
    }
}

rows.push({ " ": "", "  ": "", "   ": "", "    ": "" });

// 4. Procesar Totales Dinámicos
if (Array.isArray(parsed.totales)) {
    parsed.totales.forEach(totalItem => {
        rows.push({
            " ": "",
            "  ": "",
            "   ": safeStr(totalItem.campo).toUpperCase(),
            "    ": safeStr(totalItem.valor)
        });
    });
}

return rows.map(r => ({ json: r }));
